// PATCH: DoorDash auth/session commands for safe browser-session import and status checks.
func newAuthCmd(flags *rootFlags) *cobra.Command {
	cmd := &cobra.Command{
		Use:   "auth",
		Short: "Manage DoorDash browser-session auth without printing secrets",
	}
	cmd.AddCommand(newAuthStatusCmd(flags))
	cmd.AddCommand(newAuthLoginCmd(flags))
	cmd.AddCommand(newAuthLogoutCmd(flags))
	return cmd
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "status",
		Short: "Show safe auth/session status (cookie values are never printed)",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}
			jar, jarErr := client.NewPersistentJar(cfg.SessionFile)
			summaries := []client.CookieSummary{}
			if jarErr == nil {
				summaries = jar.Summaries()
			}
			cookieNames := make([]string, 0, len(summaries))
			for _, s := range summaries {
				cookieNames = append(cookieNames, s.Name)
			}
			report := map[string]any{
				"config_path":         cfg.Path,
				"base_url":            cfg.BaseURL,
				"session_file":        cfg.SessionFile,
				"session_file_exists": fileExists(cfg.SessionFile),
				"cookie_count":        len(summaries),
				"cookie_names":        cookieNames,
				"csrf_configured":     cfg.CSRFToken != "" || jar.CookieValue("csrf_token", "csrftoken", "csrf", "dd_csrf_token") != "",
				"auth_source":         cfg.AuthSource,
				"ready":               len(summaries) > 0 || cfg.CookieHeader != "",
			}
			if jarErr != nil {
				report["session_error"] = jarErr.Error()
				report["ready"] = false
			}
			if flags.asJSON || flags.agent {
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "session_file: %s\n", cfg.SessionFile)
			fmt.Fprintf(cmd.OutOrStdout(), "cookies: %d\n", len(summaries))
			if len(cookieNames) > 0 {
				fmt.Fprintf(cmd.OutOrStdout(), "cookie_names: %s\n", strings.Join(cookieNames, ", "))
			}
			fmt.Fprintf(cmd.OutOrStdout(), "csrf_configured: %v\n", report["csrf_configured"])
			fmt.Fprintf(cmd.OutOrStdout(), "ready: %v\n", report["ready"])
			return nil
		},
	}
}

func newAuthLoginCmd(flags *rootFlags) *cobra.Command {
	var cookieHeader string
	var cookieFile string
	var csrfToken string
	var sessionFile string
	var userAgent string
	cmd := &cobra.Command{
		Use:   "login",
		Short: "Import an account-owner-approved DoorDash Cookie header into the local encrypted-by-permissions session file",
		Long: `Import a DoorDash browser Cookie header into a 0600 JSON session jar.

Preferred secret-safe use:
  doordash-pp-cli auth login --cookie-file - < /secure/path/cookie-header.txt

Avoid passing real cookies as shell arguments unless you accept shell-history exposure.`,
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}
			if sessionFile != "" {
				cfg.SessionFile = sessionFile
			}
			if userAgent != "" {
				cfg.UserAgent = userAgent
			}
			if csrfToken != "" {
				cfg.CSRFToken = csrfToken
			}
			raw, err := readCookieInput(cookieHeader, cookieFile)
			if err != nil {
				return err
			}
			jar, err := client.NewPersistentJar(cfg.SessionFile)
			if err != nil {
				return err
			}
			if err := jar.ImportCookieHeader(raw, cfg.BaseURL); err != nil {
				return err
			}
			if err := jar.Save(); err != nil {
				return err
			}
			// Keep durable config limited to non-cookie metadata; the raw Cookie header stays out of config.toml.
			cfg.CookieHeader = ""
			if err := cfg.Save(); err != nil {
				return err
			}
			report := map[string]any{
				"saved":        true,
				"session_file": cfg.SessionFile,
				"cookie_count": len(jar.Summaries()),
				"config_path":  cfg.Path,
				"note":         "cookie values were imported but not printed",
			}
			if flags.asJSON || flags.agent {
				return printJSONFiltered(cmd.OutOrStdout(), report, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "saved %d cookies to %s (values not printed)\n", len(jar.Summaries()), cfg.SessionFile)
			return nil
		},
	}
	cmd.Flags().StringVar(&cookieHeader, "cookie-header", "", "Raw Cookie header (discouraged: may enter shell history)")
	cmd.Flags().StringVar(&cookieFile, "cookie-file", "", "Read Cookie header from file, or '-' for stdin")
	cmd.Flags().StringVar(&csrfToken, "csrf-token", "", "Optional CSRF token to send as X-CSRFToken; value is saved but never printed")
	cmd.Flags().StringVar(&sessionFile, "session-file", "", "Override session jar path")
	cmd.Flags().StringVar(&userAgent, "user-agent", "", "Override browser User-Agent")
	return cmd
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "logout",
		Short: "Remove the local DoorDash session jar and CSRF config",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}
			removed := false
			if cfg.SessionFile != "" {
				if err := os.Remove(cfg.SessionFile); err == nil {
					removed = true
				} else if !os.IsNotExist(err) {
					return err
				}
			}
			cfg.CookieHeader = ""
			cfg.CSRFToken = ""
			if err := cfg.Save(); err != nil {
				return err
			}
			out := map[string]any{"removed_session_file": removed, "session_file": cfg.SessionFile, "config_path": cfg.Path}
			if flags.asJSON || flags.agent {
				return printJSONFiltered(cmd.OutOrStdout(), out, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "removed_session_file: %v\n", removed)
			return nil
		},
	}
}

func readCookieInput(cookieHeader, cookieFile string) (string, error) {
	if cookieHeader != "" && cookieFile != "" {
		return "", fmt.Errorf("use either --cookie-header or --cookie-file, not both")
	}
	if cookieHeader != "" {
		return cookieHeader, nil
	}
	if cookieFile == "-" {
		b, err := io.ReadAll(os.Stdin)
		if err != nil {
			return "", fmt.Errorf("reading cookie header from stdin: %w", err)
		}
		return strings.TrimSpace(string(b)), nil
	}
	if cookieFile != "" {
		b, err := os.ReadFile(cookieFile)
		if err != nil {
			return "", fmt.Errorf("reading cookie header file: %w", err)
		}
		return strings.TrimSpace(string(b)), nil
	}
	return "", fmt.Errorf("cookie header required: pass --cookie-file - and provide it on stdin")
}

func fileExists(path string) bool {
	if path == "" {
		return false
	}
	_, err := os.Stat(path)
	return err == nil
}
